def validate_saml_xml_structure(xml_bytes):
    """
    Validate the basic XML structure of a SAML Response.
    Uses defused XML parsing to prevent XXE and other XML attacks.
    Returns the parsed XML root element.
    """
    if not xml_bytes:
        raise SAMLValidationError("Empty SAML response")

    # Limit response size to prevent DoS
    max_size = 1024 * 1024  # 1MB
    if len(xml_bytes) > max_size:
        raise SAMLValidationError(
            f"SAML response exceeds maximum allowed size of {max_size} bytes."
        )

    # Use a secure XML parser that disables external entities and DTDs
    parser = etree.XMLParser(
        resolve_entities=False,
        no_network=True,
        dtd_validation=False,
        load_dtd=False,
        huge_tree=False,
    )

    try:
        root = etree.fromstring(xml_bytes, parser=parser)
    except etree.XMLSyntaxError as e:
        raise SAMLValidationError(f"Invalid XML: {e}")

    # Verify root element is a SAML Response
    expected_tag = '{urn:oasis:names:tc:SAML:2.0:protocol}Response'
    if root.tag != expected_tag:
        raise SAMLValidationError(
            f"Root element is '{root.tag}', expected '{expected_tag}'."
        )

    # Verify required attributes on Response
    if not root.get('ID'):
        raise SAMLValidationError("Response is missing 'ID' attribute.")

    if not root.get('Version'):
        raise SAMLValidationError("Response is missing 'Version' attribute.")

    if root.get('Version') != '2.0':
        raise SAMLValidationError(
            f"Unsupported SAML version: '{root.get('Version')}'. Expected '2.0'."
        )

    # Check for Status element
    status = root.find('samlp:Status', SAML_NAMESPACES)
    if status is None:
        raise SAMLValidationError("Response is missing Status element.")

    status_code = status.find('samlp:StatusCode', SAML_NAMESPACES)
    if status_code is None:
        raise SAMLValidationError("Response Status is missing StatusCode element.")

    status_value = status_code.get('Value')
    if status_value != 'urn:oasis:names:tc:SAML:2.0:status:Success':
        status_message_elem = status.find('samlp:StatusMessage', SAML_NAMESPACES)
        status_message = (
            status_message_elem.text if status_message_elem is not None else 'No message'
        )
        raise SAMLValidationError(
            f"SAML authentication failed. Status: {status_value}. Message: {status_message}"
        )

    # Check for at least one Assertion
    assertions = root.findall('.//saml:Assertion', SAML_NAMESPACES)
    if not assertions:
        raise SAMLValidationError("No Assertion found in SAML response.")

    for assertion in assertions:
        if not assertion.get('ID'):
            raise SAMLValidationError("Assertion is missing 'ID' attribute.")

        # Check for Issuer
        issuer = assertion.find('saml:Issuer', SAML_NAMESPACES)
        if issuer is None or not issuer.text:
            raise SAMLValidationError("Assertion is missing Issuer element.")

        # Check for Subject with NameID
        subject = assertion.find('saml:Subject', SAML_NAMESPACES)
        if subject is None:
            raise SAMLValidationError("Assertion is missing Subject element.")

        name_id = subject.find('saml:NameID', SAML_NAMESPACES)
        if name_id is None or not name_id.text:
            raise SAMLValidationError("Assertion Subject is missing NameID.")

    # Validate all timestamps
    validate_saml_timestamps(root)

    logger.info("SAML XML structure validation passed.")
    return root


