import logging
from .xml_validator import SAML_NAMESPACES, SAMLValidationError

logger = logging.getLogger(__name__)


class SAMLResponseData:
    """Data class to hold parsed SAML response information."""

    def __init__(self):
        self.name_id = None
        self.name_id_format = None
        self.session_index = None
        self.issuer = None
        self.attributes = {}
        self.response_id = None
        self.assertion_id = None

    def __repr__(self):
        return (
            f"SAMLResponseData(name_id='{self.name_id}', "
            f"issuer='{self.issuer}', "
            f"attributes={list(self.attributes.keys())})"
        )


def extract_user_info(root):
    """
    Extract user information from a validated SAML Response XML tree.
    Returns a SAMLResponseData object.
    """
    data = SAMLResponseData()

    # Response-level info
    data.response_id = root.get('ID')

    # Get the first assertion (primary)
    assertion = root.find('.//saml:Assertion', SAML_NAMESPACES)
    if assertion is None:
        raise SAMLValidationError("No Assertion found during extraction.")

    data.assertion_id = assertion.get('ID')

    # Issuer
    issuer_elem = assertion.find('saml:Issuer', SAML_NAMESPACES)
    if issuer_elem is not None and issuer_elem.text:
        data.issuer = issuer_elem.text.strip()

    # Subject / NameID
    subject = assertion.find('saml:Subject', SAML_NAMESPACES)
    if subject is not None:
        name_id_elem = subject.find('saml:NameID', SAML_NAMESPACES)
        if name_id_elem is not None and name_id_elem.text:
            data.name_id = name_id_elem.text.strip()
            data.name_id_format = name_id_elem.get('Format', '')

    # Session Index from AuthnStatement
    authn_statement = assertion.find('saml:AuthnStatement', SAML_NAMESPACES)
    if authn_statement is not None:
        data.session_index = authn_statement.get('SessionIndex')

    # Attributes from AttributeStatement
    attr_statement = assertion.find('saml:AttributeStatement', SAML_NAMESPACES)
    if attr_statement is not None:
        for attribute in attr_statement.findall('saml:Attribute', SAML_NAMESPACES):
            attr_name = attribute.get('Name', '')
            if not attr_name:
                continue

            values = []
            for attr_value in attribute.findall('saml:AttributeValue', SAML_NAMESPACES):
                if attr_value.text:
                    # Sanitize attribute values - strip and limit length
                    val = attr_value.text.strip()[:1024]
                    values.append(val)

            if values:
                # If single value, store as string; otherwise as list
                data.attributes[attr_name] = values[0] if len(values) == 1 else values

    if not data.name_id:
        raise SAMLValidationError("Could not extract NameID from SAML assertion.")

    logger.info(
        f"Extracted SAML user info: name_id='{data.name_id}', "
        f"issuer='{data.issuer}', "
        f"attributes={list(data.attributes.keys())}"
    )

    return data


# Attribute name mappings for common SAML attributes
ATTRIBUTE_MAP = {
    'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress': 'email',
    'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname': 'first_name',
    'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname': 'last_name',
    'urn:oid:0.9.2342.19200300.100.1.3': 'email',
    'urn:oid:2.5.4.42': 'first_name',
    'urn:oid:2.5.4.4': 'last_name',
    'urn:oid:2.5.4.3': 'common_name',
    'urn:oid:1.3.6.1.4.1.5923.1.1.1.6': 'principal_name',
    'email': 'email',
    'firstName': 'first_name',
    'lastName': 'last_name',
    'displayName': 'display_name',
    'groups': 'groups',
    'role': 'role',
}


def map_attributes(raw_attributes):
    """Map SAML attribute names to friendly names using the attribute map."""
    mapped = {}
    for attr_name, attr_value in raw_attributes.items():
        friendly_name = ATTRIBUTE_MAP.get(attr_name, attr_name)
        mapped[friendly_name] = attr_value
    return mapped


