def make_saml_response(
    issue_instant=None,
    not_before=None,
    not_on_or_after=None,
    scd_not_on_or_after=None,
    name_id='testuser@example.com',
    status='urn:oasis:names:tc:SAML:2.0:status:Success',
    issuer='https://idp.example.com/saml/metadata/',
):
    """Helper to generate a SAML response XML for testing."""
    now = datetime.now(timezone.utc)
    if issue_instant is None:
        issue_instant = now.strftime('%Y-%m-%dT%H:%M:%SZ')
    if not_before is None:
        not_before = (now - timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    if not_on_or_after is None:
        not_on_or_after = (now + timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    if scd_not_on_or_after is None:
        scd_not_on_or_after = (now + timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')

    return f"""<?xml version="1.0" encoding="UTF-8"?>
<samlp:Response xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
                xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                ID="_response_123"
                Version="2.0"
                IssueInstant="{issue_instant}"
                Destination="https://your-app.example.com/saml/acs/">
    <samlp:Status>
        <samlp:StatusCode Value="{status}"/>
    </samlp:Status>
    <saml:Assertion ID="_assertion_456" Version="2.0" IssueInstant="{issue_instant}">
        <saml:Issuer>{issuer}</saml:Issuer>
        <saml:Subject>
            <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{name_id}</saml:NameID>
            <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
                <saml:SubjectConfirmationData NotOnOrAfter="{scd_not_on_or_after}"
                    Recipient="https://your-app.example.com/saml/acs/"/>
            </saml:SubjectConfirmation>
        </saml:Subject>
        <saml:Conditions NotBefore="{not_before}" NotOnOrAfter="{not_on_or_after}">
            <saml:AudienceRestriction>
                <saml:Audience>https://your-app.example.com/saml/metadata/</saml:Audience>
            </saml:AudienceRestriction>
        </saml:Conditions>
        <saml:AuthnStatement AuthnInstant="{issue_instant}" SessionIndex="_session_789">
            <saml:AuthnContext>
                <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
            </saml:AuthnContext>
        </saml:AuthnStatement>
        <saml:AttributeStatement>
            <saml:Attribute Name="email">
                <saml:AttributeValue>{name_id}</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="firstName">
                <saml:AttributeValue>Test</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="lastName">
                <saml:AttributeValue>User</saml:AttributeValue>
            </saml:Attribute>
        </saml:AttributeStatement>
    </saml:Assertion>
</samlp:Response>""".encode('utf-8')


